mapper.select:
SELECT id, name, rating, watch_status, category_id FROM television_record WHERE rating IS NOT NULL
AND created_by = #{userId}
ORDER BY rating DESC LIMIT 10

SELECT watch_status AS status, COUNT(*) AS count FROM television_record WHERE 1=1
AND created_by = #{userId}
GROUP BY watch_status ORDER BY watch_status

SELECT id, name, start_time, end_time, CASE WHEN end_time IS NOT NULL AND start_time IS NOT NULL THEN DATEDIFF(end_time, start_time) ELSE 0 END AS duration_days FROM television_record WHERE start_time IS NOT NULL AND end_time IS NOT NULL
AND created_by = #{userId}
ORDER BY duration_days DESC LIMIT 10

SELECT tc.id AS category_id, tc.name AS category_name, COUNT(tr.id) AS count FROM television_category tc LEFT JOIN television_record tr ON tc.id = tr.category_id WHERE 1=1
AND tr.created_by = #{userId}
GROUP BY tc.id, tc.name HAVING count > 0 ORDER BY count DESC LIMIT 10

SELECT YEAR(created) AS `year`, SUM(CASE WHEN watch_status = 2 THEN 1 ELSE 0 END) AS finished_count, SUM(CASE WHEN watch_status = 1 THEN 1 ELSE 0 END) AS watching_count, COUNT(*) AS total_count FROM television_record WHERE 1=1
AND created_by = #{userId}
AND YEAR(created) = #{year}
GROUP BY YEAR(created) ORDER BY `year` DESC

SELECT YEAR(created) AS `year`, QUARTER(created) AS `quarter`, SUM(CASE WHEN watch_status = 2 THEN 1 ELSE 0 END) AS finished_count, SUM(CASE WHEN watch_status = 1 THEN 1 ELSE 0 END) AS watching_count, COUNT(*) AS total_count FROM television_record WHERE 1=1
AND created_by = #{userId}
AND YEAR(created) = #{year}
AND QUARTER(created) = #{quarter}
GROUP BY YEAR(created), QUARTER(created) ORDER BY `year` DESC, `quarter` DESC

SELECT YEAR(created) AS `year`, MONTH(created) AS `month`, CONCAT(YEAR(created), '-', LPAD(MONTH(created), 2, '0')) AS year_month, SUM(CASE WHEN watch_status = 2 THEN 1 ELSE 0 END) AS finished_count, SUM(CASE WHEN watch_status = 1 THEN 1 ELSE 0 END) AS watching_count, COUNT(*) AS total_count FROM television_record WHERE 1=1
AND created_by = #{userId}
AND YEAR(created) = #{year}
AND MONTH(created) = #{month}
GROUP BY YEAR(created), MONTH(created) ORDER BY `year` DESC, `month` DESC

SELECT YEAR(created) AS `year`, WEEK(created, 1) AS `week`, CONCAT(YEAR(created), '-', LPAD(WEEK(created, 1), 2, '0')) AS year_week, SUM(CASE WHEN watch_status = 2 THEN 1 ELSE 0 END) AS finished_count, SUM(CASE WHEN watch_status = 1 THEN 1 ELSE 0 END) AS watching_count, COUNT(*) AS total_count FROM television_record WHERE 1=1
AND created_by = #{userId}
AND YEAR(created) = #{year}
AND WEEK(created, 1) = #{week}
GROUP BY YEAR(created), WEEK(created, 1) ORDER BY `year` DESC, `week` DESC
